export default function transformPicker(path: NodePath<t.JSXElement>): void {
  // Change menuWidth value from a DimensionValue to a pixel value
  convertDimensionValueToPx(path, {propName: 'menuWidth'});

  // Remove isQuiet
  removeProp(path, {propName: 'isQuiet'});

  // Change validationState="invalid" to isInvalid
  updatePropNameAndValue(path, {
    oldPropName: 'validationState',
    oldPropValue: 'invalid',
    newPropName: 'isInvalid',
    newPropValue: true
  });

  // Remove validationState="valid"
  removeProp(path, {propName: 'validationState', propValue: 'valid'});

  // Replace isLoading with loadingState
  updatePropName(path, {
    oldPropName: 'isLoading',
    newPropName: 'loadingState',
    comment: 'Replace boolean passed to isLoading with appropriate loadingState.'
  });

  // Rename onSelectionChange to onChange
  updatePropName(path, {
    oldPropName: 'onSelectionChange',
    newPropName: 'onChange'
  });

  // Rename selectedKey to value
  updatePropName(path, {
    oldPropName: 'selectedKey',
    newPropName: 'value'
  });

  // Rename defaultSelectedKey to defaultValue
  updatePropName(path, {
    oldPropName: 'defaultSelectedKey',
    newPropName: 'defaultValue'
  });
}

export default function transformSection(path: NodePath<t.JSXElement>): void {
  // Update Sections based on parent collection component
  updateComponentWithinCollection(path, {
    parentComponentName: 'Menu',
    newComponentName: 'MenuSection'
  });
  updateComponentWithinCollection(path, {
    parentComponentName: 'Picker',
    newComponentName: 'PickerSection'
  });
  updateComponentWithinCollection(path, {
    parentComponentName: 'ComboBox',
    newComponentName: 'ComboBoxSection'
  });

  // Move title prop to Header component
  movePropToNewChildComponentName(path, {
    parentComponentName: 'Menu',
    childComponentName: 'MenuSection',
    propName: 'title',
    newChildComponentName: 'Header'
  });
  movePropToNewChildComponentName(path, {
    parentComponentName: 'Picker',
    childComponentName: 'PickerSection',
    propName: 'title',
    newChildComponentName: 'Header'
  });
  movePropToNewChildComponentName(path, {
    parentComponentName: 'ComboBox',
    childComponentName: 'ComboBoxSection',
    propName: 'title',
    newChildComponentName: 'Header'
  });

  // Comment if parent collection not detected
  commentIfParentCollectionNotDetected(path);
}

function isLogicallyChanged<T extends {fileName: string}>(
  sf: T,
  node: FileNode,
  changedTsPaths: ReadonlySet<AbsoluteFsPath>,
  deletedTsPaths: ReadonlySet<AbsoluteFsPath>,
  changedResources: ReadonlySet<AbsoluteFsPath>,
): boolean {
  // A file is assumed to have logically changed if its dependencies could not be determined
  // accurately.
  if (node.failedAnalysis) {
    return true;
  }

  const sfPath = absoluteFromSourceFile(sf);

  // A file is logically changed if it has physically changed itself (including being deleted).
  if (changedTsPaths.has(sfPath) || deletedTsPaths.has(sfPath)) {
    return true;
  }

  // A file is logically changed if one of its dependencies has physically changed.
  for (const dep of node.dependsOn) {
    if (changedTsPaths.has(dep) || deletedTsPaths.has(dep)) {
      return true;
    }
  }

  // A file is logically changed if one of its resources has physically changed.
  for (const dep of node.usesResources) {
    if (changedResources.has(dep)) {
      return true;
    }
  }
  return false;
}

accept<R>(visitor: DynamicValueVisitor<R>): R {
  switch (this.code) {
    case DynamicValueReason.DYNAMIC_INPUT:
      return visitor.visitDynamicInput(this as unknown as DynamicValue<DynamicValue>);
    case DynamicValueReason.DYNAMIC_STRING:
      return visitor.visitDynamicString(this);
    case DynamicValueReason.EXTERNAL_REFERENCE:
      return visitor.visitExternalReference(
        this as unknown as DynamicValue<Reference<ts.Declaration>>,
      );
    case DynamicValueReason.UNSUPPORTED_SYNTAX:
      return visitor.visitUnsupportedSyntax(this);
    case DynamicValueReason.UNKNOWN_IDENTIFIER:
      return visitor.visitUnknownIdentifier(this);
    case DynamicValueReason.INVALID_EXPRESSION_TYPE:
      return visitor.visitInvalidExpressionType(this);
    case DynamicValueReason.COMPLEX_FUNCTION_CALL:
      return visitor.visitComplexFunctionCall(
        this as unknown as DynamicValue<FunctionDefinition>,
      );
    case DynamicValueReason.DYNAMIC_TYPE:
      return visitor.visitDynamicType(this);
    case DynamicValueReason.SYNTHETIC_INPUT:
      return visitor.visitSyntheticInput(
        this as unknown as DynamicValue<SyntheticValue<unknown>>,
      );
    case DynamicValueReason.UNKNOWN:
      return visitor.visitUnknown(this);
  }
}

function getTotalComplexity(ast: AST): number {
  const possibleBinaryOrConditional =
    extractPossibleBinaryOrConditionalFrom(ast);

  if (
    !(
      possibleBinaryOrConditional instanceof Binary ||
      possibleBinaryOrConditional instanceof Conditional
    )
  ) {
    return 0;
  }

  let total = 1;

  if (possibleBinaryOrConditional instanceof Binary) {
    const leftUnwrapped = unwrapParenthesizedExpression(
      possibleBinaryOrConditional.left,
    );
    const rightUnwrapped = unwrapParenthesizedExpression(
      possibleBinaryOrConditional.right,
    );

    if (
      leftUnwrapped instanceof Binary ||
      leftUnwrapped instanceof Conditional
    ) {
      total += getTotalComplexity(possibleBinaryOrConditional.left);
    }

    if (
      rightUnwrapped instanceof Binary ||
      rightUnwrapped instanceof Conditional
    ) {
      total += getTotalComplexity(possibleBinaryOrConditional.right);
    }
  }

  if (possibleBinaryOrConditional instanceof Conditional) {
    total +=
      getTotalComplexity(possibleBinaryOrConditional.condition) +
      getTotalComplexity(possibleBinaryOrConditional.trueExp) +
      getTotalComplexity(possibleBinaryOrConditional.falseExp);
  }

  return total;
}

export async function resolveTsconfig(
  sourceFile: string,
  tsconfigPath?: string,
): Promise<string | undefined> {
  if (tsconfigPath) {
    const resolved = resolve(tsconfigPath)
    debug("using explicit tsconfig:", resolved)
    return resolved
  }

  try {
    const result = await parse(sourceFile)

    if (!result.tsconfigFile) {
      debug("no tsconfig found for", sourceFile)
      return undefined
    }

    debug("found tsconfig:", result.tsconfigFile)

    // If this is a solution-style tsconfig (has references, no real files),
    // find the referenced config that contains `paths`
    if (result.referenced && result.referenced.length > 0) {
      debug("solution-style tsconfig detected, checking references...")

      for (const ref of result.referenced) {
        if (ref.tsconfig?.compilerOptions?.paths) {
          debug("found paths in referenced tsconfig:", ref.tsconfigFile)
          return ref.tsconfigFile
        }
      }

      // Fall back to the first referenced tsconfig
      debug("no paths found in references, using first reference")
      return result.referenced[0].tsconfigFile
    }

    return result.tsconfigFile
  } catch (error) {
    debug("tsconfig resolution failed:", error)
    return undefined
  }
}

export default async function pre(
  rootDir: string,
  options: { command: "enter"; tag: string } | { command: "exit"; tag?: string }
) {
  if (options.command === "enter") {
    try {
      await enterPre(rootDir, options.tag);
      logger.success(`Entered pre mode with tag ${pc.cyan(options.tag)}`);
      logger.info(
        "Run `changeset version` to version packages with prerelease versions"
      );
    } catch (err) {
      if (err instanceof PreEnterButInPreModeError) {
        logger.error("`changeset pre enter` cannot be run when in pre mode");
        logger.info(
          "If you're trying to exit pre mode, run `changeset pre exit`"
        );
        throw new ExitError(1);
      }
      throw err;
    }
  } else {
    try {
      await exitPre(rootDir);
      logger.success(`Exited pre mode`);
      logger.info(
        "Run `changeset version` to version packages with normal versions"
      );
    } catch (err) {
      if (err instanceof PreExitButNotInPreModeError) {
        logger.error("`changeset pre exit` can only be run when in pre mode");
        logger.info(
          "If you're trying to enter pre mode, run `changeset pre enter`"
        );
        throw new ExitError(1);
      }
      throw err;
    }
  }
}

export function createDeclarationProject(opts: CreateDeclarationProjectOptions) {
  const project = new Project({
    tsConfigFilePath: opts.tsConfigFilePath,
    manipulationSettings: {
      indentationText: IndentationText.TwoSpaces,
      newLineKind: NewLineKind.LineFeed,
    },
    compilerOptions: {
      declaration: true,
    },
  });

  const emitResult = project.emitToMemory({ emitOnlyDtsFiles: true });

  if (emitResult.getDiagnostics().length > 0) {
    printDiagnostics(emitResult.getDiagnostics());
    Deno.exit(1);
  }

  const declarationProject = new Project({
    tsConfigFilePath: opts.tsConfigFilePath,
    manipulationSettings: {
      indentationText: IndentationText.TwoSpaces,
      newLineKind: NewLineKind.LineFeed,
    },
    skipAddingFilesFromTsConfig: true,
  });

  for (const file of emitResult.getFiles())
    declarationProject.createSourceFile(file.filePath, file.text, { overwrite: true });

  const declDiagnostics = declarationProject.getPreEmitDiagnostics();
  if (declDiagnostics.length > 0) {
    console.log(declarationProject.formatDiagnosticsWithColorAndContext(declDiagnostics));
    Deno.exit(1);
  }

  return declarationProject;
}

markDirectoryAsInProject(directory: Directory) {
  if (this.isDirectoryInProject(directory))
    return;

  const inProjectCoordinator = this;
  const compilerFactory = this.#compilerFactory;
  (directory as any)._inProject = true;
  markAncestorDirs(directory);

  function markAncestorDirs(dir: Directory) {
    const ancestorDirs = Array.from(getAncestorsUpToOneInProject(dir));

    // only mark the ancestor directories as being in the project if the top one is in the project
    const topAncestor = ancestorDirs[ancestorDirs.length - 1];
    if (topAncestor == null || !inProjectCoordinator.isDirectoryInProject(topAncestor))
      return;

    for (const ancestorDir of ancestorDirs)
      (ancestorDir as any)._inProject = true;
  }

  function* getAncestorsUpToOneInProject(dir: Directory): IterableIterator<Directory> {
    if (FileUtils.isRootDirPath(dir.getPath()))
      return;
    const parentDirPath = FileUtils.getDirPath(dir.getPath());
    const parentDir = compilerFactory.getDirectoryFromCacheOnlyIfInCache(parentDirPath);
    if (parentDir == null)
      return;

    yield parentDir;

    if (!inProjectCoordinator.isDirectoryInProject(parentDir))
      yield* getAncestorsUpToOneInProject(parentDir);
  }
}

