    }

    return target;
  };
}

export function buildAuditPathIndex (
  lockfile: LockfileObject,
  vulnerableNames: Set<string>,
  opts: AuditIndexOptions
): AuditPathIndex {
  // Null-prototype record keyed by package name to avoid prototype pollution
  // from registry-supplied or lockfile-supplied names.
  const paths: AuditPathIndex = Object.create(null)
  const depTypes = opts.depTypes ?? detectDepTypes(lockfile)
  const optionalOnly = opts.optionalOnly ?? collectOptionalOnlyDepPaths(lockfile, opts.include)

  walkForPaths({
    lockfile,
    vulnerableNames,
    paths,
    depTypes,
    optionalOnly,
    include: opts.include,
    importerSegmentOf: (importerId) => importerId.replace(/\//g, '__'),
  })

  if (opts.envLockfile) {
    const envLockfileObject = envLockfileToLockfileObject(opts.envLockfile)
    walkForPaths({
      lockfile: envLockfileObject,
      vulnerableNames,
      paths,
      depTypes: detectDepTypes(envLockfileObject),
      optionalOnly: collectOptionalOnlyDepPaths(envLockfileObject, opts.include),
      include: opts.include,
      importerSegmentOf: (importerId) => importerId,
    })
  }

  return paths
}

function getDependenciesFromLicenseNode (
  licenseNode: LicenseNode
): LicensePackage[] {
  if (!licenseNode.dependencies) {
    return []
  }

  let dependencies: LicensePackage[] = []
  for (const dependencyName in licenseNode.dependencies) {
    const dependencyNode = licenseNode.dependencies[dependencyName]
    const dependenciesOfNode = getDependenciesFromLicenseNode(dependencyNode)

    dependencies = [
      ...dependencies,
      ...dependenciesOfNode,
      {
        belongsTo: dependencyNode.dev ? 'devDependencies' : 'dependencies',
        version: dependencyNode.version as string,
        name: dependencyName,
        license: dependencyNode.license as string,
        licenseContents: dependencyNode.licenseContents,
        author: dependencyNode.author as string,
        homepage: dependencyNode.homepage as string,
        description: dependencyNode.description,
        repository: dependencyNode.repository as string,
        path: dependencyNode.dir,
      },
    ]
  }

  return dependencies
}

private async executeLinkFlow(
  apiKey: string | undefined,
  databaseId: string | undefined,
  baseDir: string,
): Promise<LinkResult> {
  const client = await resolveApiClient(apiKey)

  let workspaceId: string | null = null
  let projectId: string | null = null

  if (!databaseId) {
    const resolved = await resolveDatabase(client)
    databaseId = resolved.databaseId
    workspaceId = resolved.workspaceId
    projectId = resolved.projectId
  } else {
    workspaceId = apiKey ? extractWorkspaceIdFromToken(apiKey) : null
    projectId = await resolveProjectForDatabase(client, databaseId)
  }

  const connection = await createDevConnection(client, databaseId)
  const localFilesResult = writeLocalFiles(baseDir, connection)
  const hasModels = getModelNames(baseDir).length > 0
  const environmentId = databaseId.replace(/^db_/, '')

  return {
    workspaceId: workspaceId ?? 'unknown',
    projectId: projectId ?? 'unknown',
    environmentId,
    databaseId,
    connectionString: connection.connectionString,
    localFilesResult,
    hasModels,
  }
}

public async stop(): Promise<void> {
  if (!this.child) {
    return
  }

  const result = new Promise<void>((resolve) => {
    // Terminate the child process after a timeout if it's still running. On
    // Unix, this will send a SIGTERM signal to the process, which the schema
    // engine will handle and initiate a graceful shutdown. Since it has its
    // own timeout mechanism, we shouldn't wait before sending the signal,
    // otherwise these timeouts will add up. On Windows, there are no signals
    // and the kill method will terminate the process immediately, similar to
    // SIGKILL on Unix, so we should wait to give the schema engine a chance
    // to gracefully shut down in response to EOF in stdin.
    const timer = setTimeout(
      () => {
        this.child?.kill()
        resolve()
      },
      process.platform === 'win32' ? 4000 : 0,
    ).unref()

    this.child!.on('exit', () => {
      clearTimeout(timer)
      resolve()
    })
  })

  // Close stdin to tell the schema engine to stop the RPC server and exit.
  this.child.stdin?.end()

  this.isRunning = false

  return result
}

get transaction(): Transaction {
  // Make sure we have the most up to date state.
  const state = this.store.getState();

  if (!this._transaction) {
    // Since there is currently no transaction set, make sure to create a new
    // one. Behind the scenes `state.tr` creates a new transaction for us to
    // use.
    this._transaction = state.tr;
  }

  // Check that the current transaction is valid.
  const isValid = this._transaction.before.eq(state.doc);

  // Check whether the current transaction has any already applied to it.
  const hasSteps = !isEmptyArray(this._transaction.steps);

  if (!isValid) {
    // Since the transaction is not valid we create a new one to prevent any
    // `mismatched` transaction errors.
    const tr = state.tr;

    // Now checking if any steps had been added to the previous transaction
    // and adding them to the newly created transaction.
    if (hasSteps) {
      for (const step of this._transaction.steps) {
        tr.step(step);
      }
    }

    // Make sure to store the transaction value to the instance of this
    // extension.
    this._transaction = tr;
  }

  return this._transaction;
}

function createFilePlaceholder<NodeAttributes extends AbstractNodeAttributes>({
  id,
  context,
  file,
  pos,
  view,
  fileType,
  uploadHandler,
}: {
  id: string;
  context: UploadContext;
  file: File;
  pos: number | undefined;
  view: EditorView;
  fileType: NodeType;
  uploadHandler: UploadFileHandler<NodeAttributes>;
}): FileUploader<NodeAttributes> | void {
  const tr = view.state.tr;
  const insertPos = insertFilePoint(tr.doc, isNumber(pos) ? pos : tr.selection.from, fileType);

  if (!isNumber(insertPos)) {
    // failed to find a postition to insert the file node
    return;
  }

  // create a fileUploader, which will read and/or upload the file later
  const fileUploader = uploadHandler();

  // insert the file node
  const attrs: NodeAttributes = { ...fileUploader.insert(file), id };
  tr.insert(insertPos, fileType.createChecked(attrs));

  // insert the placeholder decoration
  const payload: UploadPlaceholderPayload<NodeAttributes> = { context, fileUploader };
  setUploadPlaceholderAction(tr, { type: ActionType.ADD_PLACEHOLDER, id, pos: insertPos, payload });

  view.dispatch(tr);

  return fileUploader;
}

export function getAndIncludeFactoryVariable(
	factory: string,
	preserve: boolean,
	importSource: string | null,
	node: JSXElementBase | JSXOpeningElement | JSXOpeningFragment,
	context: InclusionContext
): Variable {
	const [baseName, nestedName] = factory.split('.');
	let factoryVariable: Variable;
	if (importSource) {
		factoryVariable = node.scope.context.getImportedJsxFactoryVariable(
			nestedName ? 'default' : baseName,
			node.start,
			importSource
		);
		if (preserve) {
			// This pretends we are accessing an included global variable of the same name
			const globalVariable = node.scope.findGlobal(baseName);
			globalVariable.includePath(UNKNOWN_PATH, context);
			// This excludes this variable from renaming
			factoryVariable.globalName = baseName;
		}
	} else {
		factoryVariable = node.scope.findGlobal(baseName);
	}
	node.scope.context.includeVariableInModule(factoryVariable, UNKNOWN_PATH, context);
	if (factoryVariable instanceof LocalVariable) {
		factoryVariable.consolidateInitializers();
		factoryVariable.addUsedPlace(node);
		node.scope.context.requestTreeshakingPass();
	}
	return factoryVariable;
}

function getDynamicallyDependentEntriesByDynamicEntry(
	dependentEntriesByModule: ReadonlyMap<Module, ReadonlySet<number>>,
	dynamicEntries: ReadonlySet<number>,
	allEntries: readonly Module[],
	getDynamicImporters: (entry: Module) => Iterable<Module>
): Map<number, Set<number>> {
	const dynamicallyDependentEntriesByDynamicEntry = new Map<number, Set<number>>();
	for (const dynamicEntryIndex of dynamicEntries) {
		const dynamicallyDependentEntries = getOrCreate(
			dynamicallyDependentEntriesByDynamicEntry,
			dynamicEntryIndex,
			getNewSet<number>
		);
		const dynamicEntry = allEntries[dynamicEntryIndex];
		for (const importer of concatLazy([
			getDynamicImporters(dynamicEntry),
			dynamicEntry.implicitlyLoadedAfter
		])) {
			const importerEntries = dependentEntriesByModule.get(importer);
			if (!importerEntries) {
				continue;
			}
			for (const entry of importerEntries) {
				dynamicallyDependentEntries.add(entry);
			}
		}
	}
	return dynamicallyDependentEntriesByDynamicEntry;
}

export const defineService = <
  // `extends object` rejects primitives, `null`, and `undefined` (while still accepting both
  // `interface` and `type` state shapes); `ServiceState` additionally rejects arrays. State must be a
  // plain object — see `ServiceState` for the deep-signal / deep-reconcile reasons.
  TState extends object,
  const TQueryInputSchemas extends OperationInputSchemas,
  const TQueryOutputSchemas extends MatchingOutputSchemas<TQueryInputSchemas>,
  const TCommandInputSchemas extends OperationInputSchemas,
  const TCommandOutputSchemas extends MatchingOutputSchemas<TCommandInputSchemas>,
>(def: {
  id: ServiceId;
  description?: string;
  initialState: ServiceState<TState>;
  queries: DefinedQueries<
    TState,
    TQueryInputSchemas,
    TQueryOutputSchemas,
    TCommandInputSchemas,
    TCommandOutputSchemas
  >;
  commands: DefinedCommands<TState, TCommandInputSchemas, TCommandOutputSchemas>;
}): ServiceDefinition<
  TState,
  DefinedQueries<
    TState,
    TQueryInputSchemas,
    TQueryOutputSchemas,
    TCommandInputSchemas,
    TCommandOutputSchemas
  >,
  DefinedCommands<TState, TCommandInputSchemas, TCommandOutputSchemas>
> => def;
